    y=np.array(vals,dtype=float); threshold=float(kv.get('threshold',kv.get('upper_limit',np.mean(y)+2*np.std(y))) or 10); lower=float(kv.get('lower_limit',-math.inf)); upper=float(kv.get('upper_limit',threshold)); z=(y-np.mean(y))/(np.std(y,ddof=1) if len(y)>1 and np.std(y,ddof=1)>0 else 1)
    exceed=[int(i) for i,v in enumerate(y) if v>threshold or v<lower or v>upper]; outliers=[int(i) for i,v in enumerate(z) if abs(v)>2.5]
    fig,ax=plt.subplots(figsize=(8.2,4.8)); ax.plot(range(len(y)),y,marker='o'); ax.axhline(threshold,linestyle='--'); ax.set_title(spec['title']); ax.grid(alpha=.28); svg=svg_from_figure(fig); plt.close(fig)
    return result(spec['title'], f'Flagged {len(exceed)} threshold exceedances and {len(outliers)} statistical outliers.', {'n':len(y),'mean':float(np.mean(y)),'std':float(np.std(y,ddof=1)) if len(y)>1 else 0,'threshold':threshold,'exceedance_indices':exceed,'outlier_indices':outliers,'missing_count_proxy':missing}, ['QA/QC flags need sensor metadata, calibration records, units, and site context.'], [{'title':spec['title']+' QA/QC series','type':'qaqc_curve','svg':svg}], ['Parse sensor series','Apply threshold limits','Compute z-score outlier proxy','Return QA flags'], 'python/numpy')

