    p=float(kv.get('probability',kv.get('likelihood',.2)) or .2); c=float(kv.get('consequence',kv.get('impact',50)) or 50); e=float(kv.get('exposure',1) or 1); v=float(kv.get('vulnerability',1) or 1); ac=float(kv.get('adaptive_capacity',0) or 0)
