def _optimization(inputs, spec):
    kv=_kv(inputs,'objective=3,2;constraints=1,1,10;2,1,14;0,1,8;maximize=true')
    c=_list_from_kv(kv,'objective',[3,2]); maximize=str(kv.get('maximize','true')).lower()!='false'
    # Grid-search two-variable nonnegative linear program with constraints rows a,b,limit
    raw=str(inputs.get('constraints') or kv.get('constraints') or '1,1,10;2,1,14;0,1,8')
    constraints=[]
