    best=None; feasible=0
    for x in np.linspace(0,20,201):
        for y in np.linspace(0,20,201):
            if all(a*x+b*y <= lim+1e-9 for a,b,lim in constraints):
                feasible+=1; val=c[0]*x+c[1]*y
                if best is None or (maximize and val>best[0]) or ((not maximize) and val<best[0]): best=(float(val),float(x),float(y))
    return result(spec['title'], 'Solved a simple two-variable constrained optimization by grid search.', {'objective_coefficients':c,'best_objective':best[0] if best else None,'best_x':best[1] if best else None,'best_y':best[2] if best else None,'feasible_grid_points':feasible}, ['MVP grid search only. Use formal solvers for production optimization.'], [bar_graph(['objective','x','y'], [best[0],best[1],best[2]] if best else [0,0,0], spec['title']+' optimum','value')], ['Parse objective and constraints','Enumerate feasible grid','Return best feasible point'], 'python/numpy')

