def _bayesian(inputs, spec):
    kv=_kv(inputs,'prior=0.1;sensitivity=0.9;specificity=0.95;positive=true')
    prior=float(kv.get('prior',.1)); sens=float(kv.get('sensitivity',.9)); specv=float(kv.get('specificity',.95)); positive=str(kv.get('positive','true')).lower()!='false'
    if positive: denom=sens*prior+(1-specv)*(1-prior); post=sens*prior/denom if denom else math.nan
    else: denom=(1-sens)*prior+specv*(1-prior); post=(1-sens)*prior/denom if denom else math.nan
    return result(spec['title'], f'Updated prior {prior:.3f} to posterior {post:.3f}.', {'prior':prior,'sensitivity':sens,'specificity':specv,'positive_evidence':positive,'posterior':post}, ['Bayesian updates depend on prior choice and evidence model quality.'], [bar_graph(['prior','posterior'], [prior,post], spec['title']+' belief update','probability')], ['Apply Bayes rule for binary evidence','Report posterior and assumptions'], 'python/numpy')

def _network(inputs, spec):
    kv=_kv(inputs,'edges=A,B;B,C;C,D;A,D;D,E;E,B;shock_node=A;attenuation=0.5')
    raw=str(inputs.get('edges') or kv.get('edges') or 'A,B;B,C;C,D;A,D;D,E;E,B')
    edges=[]; nodes=set()
    for part in raw.split(';'):
        bits=[b.strip() for b in re.split(r'[,>\-]+',part) if b.strip()]
        if len(bits)>=2: edges.append((bits[0],bits[1])); nodes.update(bits[:2])
    n=len(nodes); m=len(edges); density=m/(n*(n-1)) if n>1 else 0; cascade=min(1,density*float(kv.get('attenuation',.5))*n/3)
    return result(spec['title'], 'Computed network dependency and cascade-risk proxies.', {'node_count':n,'edge_count':m,'density':density,'cascade_potential_proxy':cascade,'edges':edges[:20]}, ['Network risk depends on edge weights, redundancy, direction, and failure dynamics.'], [bar_graph(['nodes','edges','density×10','cascade×10'], [n,m,density*10,cascade*10], spec['title']+' network profile','value')], ['Parse edge list','Compute density','Estimate cascade potential proxy'], 'python/numpy')

def _complexity(inputs, spec):
    kv=_kv(inputs,'n=10,100,1000,10000;model=nlogn;unit_cost=1')
    ns=np.array(_list_from_kv(kv,'n',[10,100,1000,10000]),dtype=float); model=str(kv.get('model','nlogn')); cost=float(kv.get('unit_cost',1))
    if model=='n2': vals=ns**2*cost
    elif model=='logn': vals=np.log2(ns)*cost
    elif model=='exp': vals=2**np.minimum(ns,30)*cost
    else: vals=ns*np.log2(ns)*cost
    return result(spec['title'], f'Estimated {model} scaling over {len(ns)} input sizes.', {'model':model,'n_values':ns.tolist(),'operation_proxy':vals.tolist(),'growth_ratio_last_first':float(vals[-1]/vals[0]) if vals[0] else None}, [], [_curve(ns,vals,spec['title']+' scaling','n','operation proxy')], ['Select complexity family','Evaluate operation proxy','Compare growth across sizes'], 'python/numpy')

def _physics_mechanics(inputs, spec):
    kv=_kv(inputs,'mass=2;velocity=12;height=5;force=10;distance=3;angle_deg=0')
    m=float(kv.get('mass',2)); v=float(kv.get('velocity',12)); h=float(kv.get('height',5)); F=float(kv.get('force',10)); d=float(kv.get('distance',3)); a=math.radians(float(kv.get('angle_deg',0))); g=9.80665
    KE=.5*m*v*v; PE=m*g*h; W=F*d*math.cos(a); p=m*v
    return result(spec['title'], 'Computed mechanics energy, work, and momentum quantities.', {'kinetic_energy_j':KE,'potential_energy_j':PE,'work_j':W,'momentum_kg_m_s':p}, ['Educational mechanics only; verify units and physical assumptions.'], [bar_graph(['KE','PE','Work','Momentum'], [KE,PE,W,p], spec['title']+' quantities','value')], ['Apply KE, PE, work, and momentum formulas'], 'python/numpy')

def _rf_link(inputs, spec):
    kv=_kv(inputs,'frequency_hz=915e6;distance_km=1;tx_power_dbm=20;tx_gain_dbi=2;rx_gain_dbi=2;losses_db=2')
    f=float(kv.get('frequency_hz',915e6)); d=float(kv.get('distance_km',1)); tx=float(kv.get('tx_power_dbm',20)); tg=float(kv.get('tx_gain_dbi',2)); rg=float(kv.get('rx_gain_dbi',2)); losses=float(kv.get('losses_db',2)); c=299792458.0; wavelength=c/f if f else math.inf; fspl=32.44+20*math.log10(max(d,1e-9))+20*math.log10(f/1e6); rx=tx+tg+rg-losses-fspl
    return result(spec['title'], f'Estimated wavelength {wavelength:.3f} m and received power {rx:.2f} dBm.', {'frequency_hz':f,'wavelength_m':wavelength,'fspl_db':fspl,'received_power_dbm_proxy':rx}, ['RF calculations are educational; comply with regulations, exposure limits, and professional design review.'], [bar_graph(['tx','gains','losses','FSPL','rx'], [tx,tg+rg,-losses,-fspl,rx], spec['title']+' link budget','dB/dBm')], ['Compute wavelength','Compute free-space path loss','Assemble link budget'], 'python/numpy')

def _electrical_power(inputs, spec):
    kv=_kv(inputs,'voltage=12;current=2;resistance=6;capacitance_f=1e-6;frequency_hz=1000;load_mw=120;capacity_mw=160')
    V=float(kv.get('voltage',12)); I=float(kv.get('current', V/float(kv.get('resistance',6) or 6))); R=float(kv.get('resistance', V/I if I else 0)); P=V*I; C=float(kv.get('capacitance_f',1e-6)); fc=1/(2*math.pi*R*C) if R and C else math.inf; load=float(kv.get('load_mw',120)); cap=float(kv.get('capacity_mw',160)); reserve=(cap-load)/load if load else math.inf
    return result(spec['title'], 'Computed circuit/power system quantities.', {'voltage_v':V,'current_a':I,'resistance_ohm':R,'power_w':P,'rc_cutoff_hz_proxy':fc,'reserve_margin_proxy':reserve}, ['Educational electrical/power screening only. Use licensed professional review for design.'], [bar_graph(['V','I','R','P','reserve%'], [V,I,R,P,reserve*100], spec['title']+' values','value')], ['Apply Ohm and power laws','Compute RC cutoff proxy','Compute reserve margin'], 'python/numpy')

def _materials(inputs, spec):
    kv=_kv(inputs,'load_n=10000;area_m2=0.01;length_m=2;delta_length_m=0.001;yield_strength_pa=250e6;youngs_modulus_pa=200e9')
    load=float(kv.get('load_n',10000)); area=float(kv.get('area_m2',.01)); L=float(kv.get('length_m',2)); dL=float(kv.get('delta_length_m',.001)); ys=float(kv.get('yield_strength_pa',250e6)); E=float(kv.get('youngs_modulus_pa',200e9)); stress=load/area if area else math.inf; strain=dL/L if L else math.inf; fos=ys/stress if stress else math.inf; estress=E*strain
    return result(spec['title'], f'Computed stress {stress:.3g} Pa, strain {strain:.3g}, and factor of safety {fos:.2f}.', {'stress_pa':stress,'strain':strain,'elastic_stress_pa':estress,'factor_of_safety_yield_proxy':fos}, ['Screening only. Not for structural certification or safety-critical design.'], [bar_graph(['stress/MPa','elastic stress/MPa','FoS'], [stress/1e6,estress/1e6,fos], spec['title']+' screening','value')], ['Compute stress','Compute strain','Compare with yield strength'], 'python/numpy')

def _structural(inputs, spec):
    kv=_kv(inputs,'span_m=6;load_n_per_m=5000;point_load_n=10000;section_modulus_m3=0.0005;allowable_stress_pa=160e6')
    L=float(kv.get('span_m',6)); w=float(kv.get('load_n_per_m',5000)); P=float(kv.get('point_load_n',0)); S=float(kv.get('section_modulus_m3',.0005)); allowable=float(kv.get('allowable_stress_pa',160e6)); M=w*L*L/8+P*L/4; stress=M/S if S else math.inf; fos=allowable/stress if stress else math.inf
    return result(spec['title'], 'Computed simple simply-supported beam screening values.', {'max_moment_nm_proxy':M,'bending_stress_pa_proxy':stress,'factor_of_safety_proxy':fos}, ['Educational screening only. Do not use for structural design or permitting.'], [bar_graph(['moment/kNm','stress/MPa','FoS'], [M/1000,stress/1e6,fos], spec['title']+' beam screen','value')], ['Use simple beam moment proxies','Convert to bending stress','Compare with allowable stress'], 'python/numpy')

def _clinical_epi(inputs, spec):
    kv=_kv(inputs,'a=40;b=60;c=20;d=80;true_positive=90;false_positive=10;false_negative=15;true_negative=85')
    a=float(kv.get('a',40)); b=float(kv.get('b',60)); c=float(kv.get('c',20)); d=float(kv.get('d',80)); risk_t=a/(a+b) if a+b else math.nan; risk_c=c/(c+d) if c+d else math.nan; rr=risk_t/risk_c if risk_c else math.nan; odds=(a*d)/(b*c) if b*c else math.nan; tp=float(kv.get('true_positive',90)); fp=float(kv.get('false_positive',10)); fn=float(kv.get('false_negative',15)); tn=float(kv.get('true_negative',85)); sens=tp/(tp+fn) if tp+fn else math.nan; specv=tn/(tn+fp) if tn+fp else math.nan
    return result(spec['title'], 'Computed epidemiology and diagnostic-test metrics.', {'risk_treated_exposed':risk_t,'risk_control_unexposed':risk_c,'relative_risk':rr,'odds_ratio':odds,'sensitivity':sens,'specificity':specv}, ['Educational/public-health analytics only. Not medical advice or clinical decision support.'], [bar_graph(['RR','OR','sensitivity','specificity'], [rr if math.isfinite(rr) else 0, odds if math.isfinite(odds) else 0, sens, specv], spec['title']+' metrics','value')], ['Compute risks and ratios','Compute diagnostic metrics','Return clinical caveats'], 'python/numpy')

def _lab_assay(inputs, spec):
    kv=_kv(inputs,'standards=0,1,2,3,4,5;signals=0.02,0.9,2.1,3.0,4.2,5.1;unknown_signal=2.6')
    standards=np.array(_list_from_kv(kv,'standards',[0,1,2,3,4,5]),dtype=float); signals=np.array(_list_from_kv(kv,'signals',[.02,.9,2.1,3.0,4.2,5.1]),dtype=float); unknown=float(kv.get('unknown_signal',2.6)); b1,b0=np.polyfit(standards,signals,1); est=(unknown-b0)/b1 if b1 else math.nan; pred=b0+b1*standards; r2=1-float(np.sum((signals-pred)**2)/max(np.sum((signals-np.mean(signals))**2),1e-12))
    return result(spec['title'], f'Estimated unknown concentration {est:.3f} from calibration curve.', {'slope':float(b1),'intercept':float(b0),'r_squared':r2,'unknown_signal':unknown,'estimated_unknown_concentration':float(est)}, ['Lab calculations require validated protocols, calibration ranges, blanks, replicates, and QA/QC review.'], [_scatter_fit(standards,signals,spec['title']+' calibration')], ['Fit calibration line','Invert signal to concentration','Report fit quality'], 'python/numpy')

