    g0=9.80665; isp=float(kv.get('isp_s',300)); m0=float(kv.get('initial_mass_kg',1000)); mf=float(kv.get('final_mass_kg',500)); mu=float(kv.get('planet_mu',3.986e14)); R=float(kv.get('planet_radius_m',6371000)); alt=float(kv.get('altitude_m',400000)); dv=isp*g0*math.log(m0/mf) if m0>mf>0 else 0; vorb=math.sqrt(mu/(R+alt)) if R+alt>0 else math.nan
